const raw = $input.first().json;

function unwrap(payload) {
  if (!payload || typeof payload !== 'object') return null;
  if (payload.current_orders !== undefined || payload.current_revenue !== undefined) {
    return payload;
  }
  if (payload.body !== undefined) {
    if (typeof payload.body === 'string') {
      try { return JSON.parse(payload.body); } catch { return null; }
    }
    return payload.body;
  }
  if (payload.data && typeof payload.data === 'object') return payload.data;
  return null;
}

const stats = unwrap(raw);
if (!stats) {
  throw new Error('Không đọc được thống kê doanh thu từ backend (port 5000)');
}

const currentOrders = Number(stats.current_orders ?? 0);
const currentRevenue = Number(stats.current_revenue ?? 0);
const currentCancelled = Number(stats.current_cancelled ?? 0);
const previousOrders = Number(stats.previous_orders ?? 0);
const previousRevenue = Number(stats.previous_revenue ?? 0);

const orderDropRate = previousOrders > 0
  ? ((previousOrders - currentOrders) / previousOrders) * 100
  : 0;

const revenueDropRate = previousRevenue > 0
  ? ((previousRevenue - currentRevenue) / previousRevenue) * 100
  : 0;

const cancelRate = currentOrders > 0
  ? (currentCancelled / currentOrders) * 100
  : 0;

let type = 'normal';
let severity = 'info';
let alert_level = 'normal';
let message = 'Hoạt động bán hàng bình thường';

if (currentOrders === 0) {
  type = 'low_order_rate';
  severity = 'critical';
  alert_level = 'critical';
  message = `Không có đơn hàng trong ngày hôm nay. Doanh thu hiện tại: ${currentRevenue.toLocaleString('vi-VN')}đ`;
} else if (orderDropRate >= 50) {
  type = 'order_drop';
  severity = 'warning';
  alert_level = 'warning';
  message = `Số đơn giảm ${orderDropRate.toFixed(1)}% so với hôm qua. Hôm nay: ${currentOrders} đơn, hôm qua: ${previousOrders} đơn`;
} else if (revenueDropRate >= 50) {
  type = 'low_revenue';
  severity = 'warning';
  alert_level = 'warning';
  message = `Doanh thu giảm ${revenueDropRate.toFixed(1)}% so với hôm qua. Hôm nay: ${currentRevenue.toLocaleString('vi-VN')}đ, hôm qua: ${previousRevenue.toLocaleString('vi-VN')}đ`;
} else if (cancelRate >= 30) {
  type = 'high_cancel_rate';
  severity = 'critical';
  alert_level = 'critical';
  message = `Tỷ lệ hủy đơn cao: ${cancelRate.toFixed(1)}%. Đơn hủy: ${currentCancelled}/${currentOrders}`;
}

return [{
  type,
  severity,
  alert_level,
  status: 'open',
  message,
  current_orders: currentOrders,
  previous_orders: previousOrders,
  current_revenue: currentRevenue,
  previous_revenue: previousRevenue,
  order_drop_rate: orderDropRate.toFixed(1),
  revenue_drop_rate: revenueDropRate.toFixed(1),
  cancel_rate: cancelRate.toFixed(1),
}];

